import React, { useState, useEffect } from 'react';
import axios from 'axios';

function CareTipsList({ onSelect }) {
  const [plants, setPlants] = useState([]);
  const [filter, setFilter] = useState('All');
  const topics = ['All', 'Watering', 'Sunlight', 'Soil', 'Pruning', 'Temperature'];

  useEffect(() => {
    axios.get('http://localhost:5000/api/plants')
      .then(res => setPlants(res.data))
      .catch(() => alert('Failed to fetch plants'));
  }, []);

  // Flatten care tips from plants into an array for display
  const careTipsArray = [];

  plants.forEach(plant => {
    Object.entries(plant.careTips || {}).forEach(([topicKey, tip]) => {
      if (tip && (filter === 'All' || filter.toLowerCase() === topicKey)) {
        careTipsArray.push({
          plantId: plant._id,
          plantName: plant.name,
          topic: topicKey,
          tip,
        });
      }
    });
  });

  return (
    <div>
      <h2>Plant Care Tips</h2>
      <div>
        {topics.map(t => (
          <button
            key={t}
            onClick={() => setFilter(t)}
            style={{
              margin: '5px',
              backgroundColor: filter === t ? 'green' : 'lightgray',
              color: filter === t ? 'white' : 'black',
            }}
          >
            {t}
          </button>
        ))}
      </div>

      <div>
        {careTipsArray.map(({ plantId, plantName, topic, tip }, index) => (
          <div
            key={index}
            onClick={() => onSelect(plantId)}
            style={{
              border: '1px solid #ccc',
              margin: '10px',
              padding: '10px',
              cursor: 'pointer',
              backgroundColor: '#f9f9f9',
            }}
          >
            <h3>{plantName} - {topic.charAt(0).toUpperCase() + topic.slice(1)}</h3>
            <p>{tip}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default CareTipsList;
